void JPH_MotionProperties_SetLinearDamping(JPH_MotionProperties *self, float inLinearDamping);
/// Get angular damping: dw/dt = -c * w. c must be between 0 and 1 but is usually close to 0.
float JPH_MotionProperties_GetAngularDamping(const JPH_MotionProperties *self);
void JPH_MotionProperties_SetAngularDamping(JPH_MotionProperties *self, float inAngularDamping);
